%dw 2.0
output application/json
---
{
  "allOrNone": false,
  "compositeRequest": [
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT Asset__r.ExternalId__c, Asset__r.ModelCode__c, Asset__r.Product2.Name, Asset__r.Product2.VehicleFamilyCode__c, Asset__r.StockCode__c, Asset__r.Version__c, CreatedDate, DealerNetServiceCode__c, Description, EffectiveDate, ExternalIdDealerNet__c, MainContact__r.ContactPreference__c, OrderNumber, Store__r.DealerNetExternalId__c, TotalAmount FROM Order WHERE Id = '"++ vars.orderId ++"'",
      "referenceId": "OrderQuery"
    },
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT ListPrice, OrderId, UnitPrice, Discount__c FROM OrderItem WHERE OrderId = '"++ vars.orderId ++"'",
      "referenceId": "OrderItemsQuery"
    },
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT ApprovedInstallmentAmount__c, CheckAgency__c, CheckingAccount__c, ConsortiumGroup__c, ConsortiumQuote__c, CreatedDate, Description__c, DueDate__c, FinancingBank__c, InterestAmount__c, LastModifiedDate, NumberInstallmentsApproved__c, Order__c, Order__r.Account.CPFCNPJ__c, PaymentCondition__r.ExternalId__c, PaymentCondition__r.Name, UsedVehicleEvaluation__r.VehiclePlate__c, UsedVehicleEvaluation__r.ExternalId__c FROM Installment__c WHERE Order__r.Id = '" ++ vars.orderId ++ "'",
      "referenceId": "InstallmentsQuery"
    }
  ]
}

%dw 2.0
output application/json
---
{
  "allOrNone": false,
  "compositeRequest": [
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT BookingCode__c, ExternalId__c, Opportunity__r.DealerNetServiceCode__c, Opportunity__r.RecordType.Name, Price, ReservationDateTime__c, ReservationExpirationDateTime__c, Status FROM Asset WHERE Id = '" ++ vars.assetId ++ "'",
      "referenceId": "AssetQuery"
    }
  ]
}

%dw 2.0
output application/json
---
{
  "allOrNone": false,
  "compositeRequest": [
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT CaminhoPrice__c, FipeValue__c, InformedValue__c, LastAutoAvaliarSync__c, ModelId__c, ModelYear__c, Name, PriceObservation__c, Renavam__c, Status__c, Store__r.ExternalId__c, ValuationGoal__c, ValuationObs__c, ValuationValue__c, VehicleColorId__c, VehicleMileage__c, VehiclePlate__c, VehicleVIN__c, TYPEOF Owner WHEN User THEN DealerNetCode__c END FROM AssessmentUsed__c WHERE Id = '" ++ vars.assesmentId ++ "'",
      "referenceId": "AssessmentUsedQuery"
    },
    {
      "method": "GET",
      "url": "/services/data/v63.0/query?q=SELECT Order__c, Quote__r.Account.ExternalId__c, Quote__r.Opportunity.DealerNetServiceCode__c FROM Installment__c WHERE UsedVehicleEvaluation__c = '" ++ vars.assesmentId ++ "' LIMIT 1",
      "referenceId": "InstallmentsQuery"
    }
  ]
}

